import tarfile

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        if not os.path.isfile(tar_path):
            return False

        os.makedirs(dest_path, exist_ok=True)

        with tarfile.open(tar_path, 'r:*') as tar:
            # Use the safe extraction filter if available (Python 3.12+)
            try:
                tar.extractall(path=dest_path, filter='data')
            except TypeError:
                # Fallback for older Python versions: manually vet each member
                for member in tar.getmembers():
                    # Reject absolute paths and paths containing parent directory references
                    if member.name.startswith('/') or '..' in member.name.split('/'):
                        return False
                    tar.extract(member, dest_path)

        return True
    except Exception:
        return False

