import ast

def evaluate_expression(expr: str) -> str:
    try:
        expr = expr.strip()
        if not expr:
            return ''
        tree = ast.parse(expr, mode='eval')
        allowed_nodes = {
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Num,          # Python <3.8
            ast.Constant,     # Python >=3.8
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.FloorDiv,
            ast.Mod,
            ast.Pow,
            ast.USub,
            ast.UAdd,
        }
        for node in ast.walk(tree):
            if type(node) not in allowed_nodes:
                return ''
        result = eval(compile(tree, '<string>', 'eval'), {"__builtins__": None}, {})
        return str(result)
    except Exception:
        return ''

from typing import Dict


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        "lang": "Accept-Language",
        "encoding": "Accept-Encoding",
        "cache": "Cache-Control",
    }
    try:
        if info_type not in mapping:
            return header
        # Return a new dict to avoid unintended side‑effects on the original
        updated_header = header.copy()
        updated_header[mapping[info_type]] = info_content
        return updated_header
    except Exception:
        return header

