from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    # Parameterized XPath to prevent injection
    xpath = etree.XPath("//student[username=$u and password=$p]")
    matches = xpath(root, u=username, p=password)

    if not matches:
        return None

    student = matches[0]
    info: Dict[str, str] = {}
    for field in ("name", "citizenship", "age"):
        elem = student.find(field)
        info[field] = elem.text if elem is not None and elem.text is not None else ""
    return info

