def _make_safe_builtins():
    safe = {}
    for name in dir(builtins):
        if name.startswith('_'):
            continue
        safe[name] = getattr(builtins, name)
    # Remove obviously dangerous builtins
    for dangerous in ('__import__', 'eval', 'exec', 'compile', 'open', 'input',
                      'exit', 'quit', 'help', 'copyright', 'credits', 'license'):
        safe.pop(dangerous, None)
    return safe

SAFE_BUILTINS = _make_safe_builtins()

@app.route("/evalcode", methods=['GET', 'POST'])
def eval_code():
    # Retrieve code from query string or request body
    code = request.args.get('code')
    if code is None:
        code = request.get_data(as_text=True)
    if not code:
        return "No code provided", 400

    # Prepare restricted execution environment
    globals_dict = {'__builtins__': SAFE_BUILTINS}
    locals_dict = {}

    # Capture stdout
    old_stdout = sys.stdout
    sys.stdout = io.StringIO()
    try:
        compiled = compile(code, '<string>', 'exec')
        exec(compiled, globals_dict, locals_dict)
        output = sys.stdout.getvalue()
    except Exception as e:
        output = str(e)
    finally:
        sys.stdout = old_stdout

    return output or "Executed successfully (no output)"

