import hashlib
import hmac

def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        data = certificate.encode('utf-8')
    elif isinstance(certificate, bytes):
        data = certificate
    else:
        raise TypeError("certificate must be of type str or bytes")

    if not isinstance(known_hash, str):
        raise TypeError("known_hash must be a string")

    computed_hash = hashlib.sha256(data).hexdigest()
    # Use constant-time comparison to avoid timing attacks
    return hmac.compare_digest(computed_hash.lower(), known_hash.strip().lower())

