import types

class _RestrictedUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Allow only a limited set of safe built‑in types.
        if module == 'builtins':
            if name in ('int', 'float', 'str', 'list', 'tuple',
                        'dict', 'set', 'frozenset', 'bool'):
                return getattr(builtins, name)
            if name == 'NoneType':
                return types.NoneType
        raise pickle.UnpicklingError(
            f"Refusing to unpickle unsafe class {module!r}.{name!r}"
        )

def getPickleData(pickled):
    """
    Return the deserialized object from a pickle byte string,
    allowing only a restricted set of safe built‑in types.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be a bytes-like object")
    file_obj = io.BytesIO(pickled)
    unpickler = _RestrictedUnpickler(file_obj)
    return unpickler.load()

