import base64
import json

class Token:
    def __init__(self, valid=False, data=None):
        self.valid = valid
        self.data = data

def confirmAuth(headers):
    token_b64 = headers.get('AuthToken') or headers.get('auth-token') or headers.get('Authorization')
    if not token_b64:
        return None
    try:
        token_bytes = base64.b64decode(token_b64)
        token_str = token_bytes.decode('utf-8')
        token_dict = json.loads(token_str)
        valid = bool(token_dict.get('valid', False))
        data = token_dict.get('data')
        token = Token(valid=valid, data=data)
    except Exception:
        return None
    if isinstance(token, Token) and token.valid:
        return token.data
    return None
